#!/bin/env python
#
# Evaluate results generated by any of the method scripts (PIV, Delaunay, Voronoi, RBF).
#

import numpy as np
from pathlib import Path
import csv


def sample_velocities(
    xs: np.ndarray, ys: np.ndarray, nu: float, t: float
) -> np.ndarray:
    us = np.sin(xs) * np.cos(ys) * np.exp(-2 * nu * t)
    vs = np.cos(xs) * np.sin(ys) * np.exp(-2 * nu * t)
    return np.column_stack([us, vs])


def calculate_error(expected: np.ndarray, actual: np.ndarray):
    errors = np.sum(np.square(expected - actual), axis=1)
    return np.mean(errors)


def run(infile, outfile, timestep: float, dissipation: float):
    csv_reader = csv.reader(infile)

    t = 0.0
    while True:
        try:  # try to read next 4 lines from the csv
            xs = np.array(next(csv_reader), dtype=np.float32)
            ys = np.array(next(csv_reader), dtype=np.float32)
            us = np.array(next(csv_reader), dtype=np.float32)
            vs = np.array(next(csv_reader), dtype=np.float32)
        except StopIteration:
            break  # end of data, stop

        expected_velocities = sample_velocities(xs, ys, dissipation, t)
        actual_velocities = np.column_stack([us, vs])

        error = calculate_error(expected_velocities, actual_velocities)
        print(error, file=outfile)

        t += timestep


if __name__ == "__main__":
    from argparse import ArgumentParser

    parser = ArgumentParser(
        description="Evaluate the results produced by a method script"
    )
    parser.add_argument(
        "--infile", required=True, type=Path, help="file to read results from"
    )
    parser.add_argument(
        "--outfile", required=True, type=Path, help="file to write errors to"
    )
    parser.add_argument(
        "--timestep",
        required=True,
        help="timestep data was generated with",
        type=float,
    )
    parser.add_argument(
        "--dissipation",
        required=True,
        help="dissipation constant data was generated with",
        type=float,
    )

    arguments = parser.parse_args()
    infile = open(arguments.infile, "r")
    outfile = open(arguments.outfile, "w")

    run(infile, outfile, arguments.timestep, arguments.dissipation)
